import{_ as i,o as a,c as l,ac as s}from"./chunks/framework.DnBnwVZk.js";const _=JSON.parse('{"title":"使用FreeFileSync自动同步文件夹中的文件","description":"","frontmatter":{"date":"2019-05-14T00:00:00.000Z","categories":["知识&技巧"],"tags":["FileSync"],"publish":true},"headers":[],"relativePath":"views/skill/windows/FileSync.md","filePath":"views/skill/windows/FileSync.md","lastUpdated":1775654397000}'),t={name:"views/skill/windows/FileSync.md"};function n(p,e,r,c,o,d){return a(),l("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1557792000000"},[...e[0]||(e[0]=[s('<h1 id="使用freefilesync自动同步文件夹中的文件" tabindex="-1">使用FreeFileSync自动同步文件夹中的文件 <a class="header-anchor" href="#使用freefilesync自动同步文件夹中的文件" aria-label="Permalink to &quot;使用FreeFileSync自动同步文件夹中的文件&quot;">​</a></h1><ol><li><p>下载安装文件并安装</p></li><li><p>打开桌面的FreeFileSync</p></li><li><p>在打开的页面中选中需同步的两个文件夹，点击比较-&gt;点击同步，然后文件-&gt;另存为批处理xxx.ffs_batch</p></li><li><p>打开桌面的RealTimeSync，导入刚才另存的ffs_batch文件</p></li><li><p>设置扫描间隔等，然后另存为ffs_real文件</p></li><li><p>桌面新建快捷方式，输入以下链接，其中第一部分为RealTimeSync.exe的路径，后面跟一个空格，第二部分为上一步另存的ffs_real文件</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;C:\\Program Files\\FreeFileSync\\RealTimeSync.exe&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C:\\Users\\kk\\Documents\\FileSync\\SourceCode.ffs_real&quot;</span></span></code></pre></div></li><li><p>打开文件浏览器，输入shell:startup进入启动菜单，将刚才的快捷方式拖入</p></li><li><p>完成，此时会自动同步并且开机启动</p></li></ol>',2)])])}const f=i(t,[["render",n]]);export{_ as __pageData,f as default};
